	from ._windows import ProactorEventLoop

@with_logger
class _QEventLoop(asyncio.BaseEventLoop):
  # Class data

class QEventLoopSelector(_QEventLoop, _SelectorEventLoop):
pass

if os.name == 'nt':
    class QEventLoopIOCP(_QEventLoop, _ProactorEventLoop):
    pass
