Well I said that and then discovered that something like following let me handle the IntegrityError while using the mixin:

```
class ReversionViewMixin(object):
    def dispatch(self, *args, **kwargs):
        with transaction.atomic(), reversion.create_revision():
            response = super(ReversionViewMixin, self).dispatch(*args, **kwargs)
            reversion.set_user(self.request.user)
            return response

class FooList(ReversionViewMixin, generics.ListCreateAPIView):
    ...
    
    def perform_create(self, serializer):
        try:
            with transaction.atomic(), reversion.create_revision():
                serializer.save(
                    created_by=self.request.user,
                    modified_by=self.request.user,
                )
        except IntegrityError:
            ...

            try:
                foo = Foo.objects.get(bar=value)
            except Foo.DoesNotExist:
                foo = None
                        
            if foo:
                raise ValidationError("Integrity error: Foo already exists with pk '%s'." % foo.pk)
            
            raise ValidationError("Unexpected Integrity Error Encountered.")
```

